def decimal_to_binary_fraction(decimal_number, max_precision=32):
    if not isinstance(decimal_number, (int, float)):
        raise TypeError("Giriş bir tam sayı veya ondalık sayı olmalıdır.")

    if decimal_number < 0:
        return "-" + decimal_to_binary_fraction(abs(decimal_number), max_precision)

    integer_part = int(decimal_number)
    fractional_part = decimal_number - integer_part

    binary_integer = bin(integer_part)[2:]

    binary_fraction = ""
    count = 0
    while fractional_part > 0 and count < max_precision:
        fractional_part *= 2
        bit = int(fractional_part)
        binary_fraction += str(bit)
        fractional_part -= bit
        count += 1

    if not binary_fraction:
        return binary_integer
    else:
        return binary_integer + "." + binary_fraction
